use std::cmp::Ordering;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    fn compute_popcount_depth(x: i64) -> usize {
        let mut depth = 0;
        let mut val = x;
        while val > 0 {
            val = val.count_ones() as i64;
            depth += 1;
        }
        depth
    }

    let n = nums.len();
    let max_depth = 5;
    let mut popcount_depths = vec![0; n];
    for i in 0..n {
        popcount_depths[i] = compute_popcount_depth(nums[i]);
    }

    struct FenwickTree {
        n: usize,
        tree: Vec<i32>,
    }

    impl FenwickTree {
        fn new(size: usize) -> Self {
            let tree = vec![0; size + 1];
            FenwickTree { n: size, tree }
        }

        fn update(&mut self, idx: usize, delta: i32) {
            let mut i = idx;
            while i <= self.n {
                self.tree[i] += delta;
                i += i & -i;
            }
        }

        fn query(&self, idx: usize) -> i32 {
            let mut res = 0;
            let mut i = idx;
            while i > 0 {
                res += self.tree[i];
                i -= i & -i;
            }
            res
        }
    }

    let mut ft = vec![FenwickTree::new(n); max_depth + 1];

    for i in 0..n {
        let d = popcount_depths[i];
        if d <= max_depth {
            ft[d].update(i + 1, 1);
        }
    }

    let mut answer = Vec::new();

    for q in queries {
        if q[0] == 1 {
            let l = q[1] as usize;
            let r = q[2] as usize;
            let k = q[3] as usize;
            if k > max_depth {
                answer.push(0);
                continue;
            }
            let count = ft[k].query(r + 1) - ft[k].query(l);
            answer.push(count as i64);
        } else {
            let idx = q[1] as usize;
            let val = q[2];
            let old_val = nums[idx];
            let old_depth = popcount_depths[idx];
            if old_depth <= max_depth {
                ft[old_depth].update(idx + 1, -1);
            }
            nums[idx] = val;
            let new_depth = compute_popcount_depth(val);
            popcount_depths[idx] = new_depth;
            if new_depth <= max_depth {
                ft[new_depth].update(idx + 1, 1);
            }
        }
    }

    answer
}
